modules.fpm_unpack:
// full module source
`timescale 1ns/1ps
module fpm_unpack(
    input  [31:0] a,
    input  [31:0] b,
    output        a_sign,
    output [7:0]  a_exp,
    output [23:0] a_mant,
    output        b_sign,
    output [7:0]  b_exp,
    output [23:0] b_mant,
    output        a_is_nan,
    output        a_is_inf,
    output        a_is_zero,
    output        b_is_nan,
    output        b_is_inf,
    output        b_is_zero
);
    // Unpack a
    assign a_sign = a[31];
    assign a_exp  = a[30:23];
    // mantissa: implicit leading 1 for normal numbers, no implicit 1 for denormals/zero
    assign a_mant = (a[30:23] == 8'h00) ? {1'b0, a[22:0]}   // denormal or zero: no implicit 1
                                         : {1'b1, a[22:0]};  // normal: implicit 1

    // Special cases for a
    assign a_is_zero = (a[30:0] == 31'h0);                          // exp=0, mantissa=0
    assign a_is_inf  = (a[30:23] == 8'hFF) && (a[22:0] == 23'h0);  // exp=FF, mantissa=0
    assign a_is_nan  = (a[30:23] == 8'hFF) && (a[22:0] != 23'h0);  // exp=FF, mantissa!=0

    // Unpack b
    assign b_sign = b[31];
    assign b_exp  = b[30:23];
    assign b_mant = (b[30:23] == 8'h00) ? {1'b0, b[22:0]}
                                         : {1'b1, b[22:0]};

    // Special cases for b
    assign b_is_zero = (b[30:0] == 31'h0);
    assign b_is_inf  = (b[30:23] == 8'hFF) && (b[22:0] == 23'h0);
    assign b_is_nan  = (b[30:23] == 8'hFF) && (b[22:0] != 23'h0);

endmodule

modules.fpm_multiply:
`timescale 1ns/1ps
module fpm_multiply(
    input         a_sign,
    input  [7:0]  a_exp,
    input  [23:0] a_mant,
    input         b_sign,
    input  [7:0]  b_exp,
    input  [23:0] b_mant,
    output        result_sign,
    output [47:0] product,
    output [9:0]  raw_exp
);
    assign result_sign = a_sign ^ b_sign;
    assign product     = a_mant * b_mant;
    assign raw_exp     = a_exp + b_exp - 10'd127;
endmodule

modules.fpm_normalize:
`timescale 1ns/1ps
module fpm_normalize(
    input  [47:0] product,
    input  [9:0]  raw_exp,
    output [22:0] norm_frac,
    output [9:0]  norm_exp,
    output        guard,
    output        sticky
);
    wire overflow = product[47]; // bit47=1 means product >= 2.0 in 2.mantissa format

    assign norm_frac = overflow ? product[46:24] : product[45:23];
    assign norm_exp  = overflow ? raw_exp + 10'd1 : raw_exp;
    assign guard     = overflow ? product[23]     : product[22];
    assign sticky    = overflow ? |product[22:0]  : |product[21:0];

endmodule

modules.fpm_round_pack:
// full module source
module fpm_round_pack(
    input         sign,
    input  [22:0] norm_frac,
    input  [9:0]  norm_exp,
    input         guard,
    input         sticky,
    output reg [31:0] result,
    output reg        overflow,
    output reg        underflow
);

    wire round_up;
    wire [23:0] rounded_frac; // 24 bits to capture carry
    wire [9:0]  adj_exp;
    wire [22:0] final_frac;
    wire [9:0]  final_exp;
    wire        carry;

    // Round to nearest, ties to even
    assign round_up = guard & (sticky | norm_frac[0]);

    // Add rounding bit to the 23-bit stored fraction
    assign rounded_frac = {1'b0, norm_frac} + {23'b0, round_up};

    assign carry = rounded_frac[23]; // carry out means fraction overflowed

    // If carry, fraction becomes 0 and exponent increments
    assign adj_exp = carry ? (norm_exp + 10'd1) : norm_exp;
    assign final_exp = adj_exp;
    assign final_frac = carry ? 23'b0 : rounded_frac[22:0];

    // Treat norm_exp as signed 10-bit to detect negative (underflow) exponents
    wire signed [9:0] norm_exp_signed;
    assign norm_exp_signed = $signed(norm_exp);

    wire signed [9:0] final_exp_signed;
    assign final_exp_signed = $signed(final_exp);

    always @(*) begin
        overflow  = 0;
        underflow = 0;
        result    = 32'b0;

        if (norm_exp_signed <= 10'sd0) begin
            // Underflow - exponent is zero or negative, return zero
            underflow = 1;
            result = 32'b0;
        end else if (norm_exp_signed >= 10'sd255) begin
            // Overflow - return infinity
            overflow = 1;
            result = {sign, 8'hFF, 23'h0};
        end else begin
            // Normal case - apply rounding
            if (final_exp_signed >= 10'sd255) begin
                // Rounding caused overflow
                overflow = 1;
                result = {sign, 8'hFF, 23'h0};
            end else if (final_exp_signed <= 10'sd0) begin
                underflow = 1;
                result = 32'b0;
            end else begin
                result = {sign, final_exp[7:0], final_frac};
            end
        end
    end

endmodule

modules.fpm_special:
`timescale 1ns/1ps
module fpm_special(
    input         a_is_nan,
    input         a_is_inf,
    input         a_is_zero,
    input         b_is_nan,
    input         b_is_inf,
    input         b_is_zero,
    input         result_sign,
    output        is_special,
    output reg [31:0] special_result
);
    // Special case detection
    wire is_nan_result  = a_is_nan | b_is_nan | (a_is_inf & b_is_zero) | (a_is_zero & b_is_inf);
    wire is_inf_result  = (a_is_inf | b_is_inf) & ~is_nan_result;
    wire is_zero_result = (a_is_zero | b_is_zero) & ~is_nan_result;

    assign is_special = is_nan_result | is_inf_result | is_zero_result;

    always @(*) begin
        if (is_nan_result)
            special_result = 32'h7FC00000; // Quiet NaN
        else if (is_inf_result)
            special_result = {result_sign, 8'hFF, 23'h0}; // Signed Inf
        else if (is_zero_result)
            special_result = {result_sign, 31'h0}; // Signed zero
        else
            special_result = 32'h0;
    end
endmodule
